module simple_pwm #(
    parameter integer COUNTER_WIDTH = 8
) (
    input  logic                     clk,
    input  logic                     rst_n,
    input  logic                     enable,
    input  logic [COUNTER_WIDTH-1:0] duty_cycle,
    input  logic [COUNTER_WIDTH-1:0] period,
    output logic                     pwm_out
);

    // Internal counter state is the primary cycle-model observable state.
    logic [COUNTER_WIDTH-1:0] counter;
    logic [COUNTER_WIDTH-1:0] counter_plus_one;
    logic [COUNTER_WIDTH-1:0] counter_next;
    logic                     pwm_out_next;

    // Precompute increment outside procedural logic to keep arithmetic explicit.
    assign counter_plus_one = counter + {{(COUNTER_WIDTH-1){1'b0}}, 1'b1};

    // S0_COUNTER_UPDATE and S1_COMPARE_OUTPUT are implemented in one cycle:
    // - compute next counter value from current state/inputs
    // - compute pwm_out from current counter vs duty_cycle
    // Both are registered on the same clock edge, giving latency=1 from edge to observable output.
    always @(*) begin
        counter_next = {COUNTER_WIDTH{1'b0}};
        pwm_out_next = 1'b0;

        if (enable == 1'b1) begin
            if ((period != {COUNTER_WIDTH{1'b0}}) && (counter_plus_one < period)) begin
                counter_next = counter_plus_one;
            end else begin
                counter_next = {COUNTER_WIDTH{1'b0}};
            end

            // Handshake/phase rule: pwm_out directly reflects counter<duty_cycle for this cycle.
            if (counter < duty_cycle) begin
                pwm_out_next = 1'b1;
            end else begin
                pwm_out_next = 1'b0;
            end
        end else begin
            // FM3 idle behavior and invariant: disable forces counter and pwm_out low.
            counter_next = {COUNTER_WIDTH{1'b0}};
            pwm_out_next = 1'b0;
        end
    end

    // Async assert, sync deassert reset contract:
    // rst_n low immediately clears architectural state and output.
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            counter  <= {COUNTER_WIDTH{1'b0}};
            pwm_out  <= 1'b0;
        end else begin
            counter  <= counter_next;
            pwm_out  <= pwm_out_next;
        end
    end

endmodule

